import json

# Load all NYSE non-ETF stocks
stockinfo_file = locals()['var_functions.query_db:26']
with open(stockinfo_file, 'r') as f:
    nyse_stock_data = json.load(f)

symbol_to_name = {item['Symbol']: item['Company Description'] for item in nyse_stock_data}
nyse_symbols = list(symbol_to_name.keys())

# Create a list to track stock performance
stock_performance = []

# Query each stock's 2017 data
for i, symbol in enumerate(nyse_symbols):
    try:
        # This will be replaced with actual query in next steps
        # For now, just track that we have this symbol
        stock_performance.append({
            'symbol': symbol,
            'company_name': symbol_to_name[symbol],
            'status': 'pending'
        })
    except Exception as e:
        stock_performance.append({
            'symbol': symbol,
            'company_name': symbol_to_name[symbol],
            'status': 'error',
            'error': str(e)
        })

print('__RESULT__:')
print(json.dumps({
    'total_symbols': len(nyse_symbols),
    'sample_symbol': nyse_symbols[0],
    'sample_name': symbol_to_name[nyse_symbols[0]]
}))

