import json

# Load all the query results we have so far
results = []

# Load and parse each query result
try:
    result1 = locals()['var_functions.query_db:94']
    results.extend(result1)
except:
    pass

try:
    result2 = locals()['var_functions.query_db:96']
    results.extend(result2)
except:
    pass

try:
    result3 = locals()['var_functions.query_db:98']
    results.extend(result3)
except:
    pass

try:
    result4 = locals()['var_functions.query_db:100']
    results.extend(result4)
except:
    pass

# Filter for stocks with more up days than down days and valid data
winners = []
for stock in results:
    if (stock['up_days'] != 'nan' and stock['down_days'] != 'nan' and 
        float(stock['up_days']) > float(stock['down_days'])):
        winners.append({
            'symbol': stock['symbol'],
            'up_days': float(stock['up_days']),
            'down_days': float(stock['down_days']),
            'total_days': int(stock['total_days'])
        })

# Sort by best performance (most up days vs down days)
winners_sorted = sorted(winners, key=lambda x: x['up_days'] - x['down_days'], reverse=True)

print('__RESULT__:')
print(json.dumps({
    'winners_found': len(winners_sorted),
    'top_winners': winners_sorted[:10],
    'all_results_checked': len(results)
}))

